import clsx from 'clsx';
import { CSSProperties, ReactNode } from 'react';

export interface DimmerProps {
  active?: boolean;
  loader?: boolean;
  children?: ReactNode;
  className?: string;
  style?: CSSProperties;
}
export function Dimmer(props: DimmerProps) {
  if (!props.active) return null;
  return (
    <div className={clsx('qh-dimmer', props.className)} style={props.style}>
      {props.loader && <div className="qh-loader" />}
      <span className="qh-dimmer--content">{props.children}</span>
    </div>
  );
}
