import { range } from 'lodash-es';
import { ReactNode, useState } from 'react';
import { useOnChangeInRender } from '../hooks/state';
import {
  getFieldGroupValueFunction,
  getFieldValue,
  getTemplate,
} from '../selectors/QHGridSelector';
import {
  Grouping,
  ObjectLiteral,
  RowClickHandler,
  RowLevelPropsCalc,
  RowLevelStyleCalc,
} from '../types';
import { QHGridColumnConfig } from './types';
import clsx from 'clsx';
import { QIcon } from '../components/Icon';

interface QHGridBodyProps<Data extends ObjectLiteral, ATI> {
  visibleColumns: QHGridColumnConfig<Data, ATI>[];
  grouping: Grouping<Data, ATI>[];
  slicedData: Data[];
  rowLevelStyleCalc?: RowLevelStyleCalc<Data>;
  rowLevelPropsCalc?: RowLevelPropsCalc<Data>;
  onRowClick?: RowClickHandler<Data>;
  additionalTemplateInfo: ATI;
  startIndex: number;
  itemKeyMap: (item: Data) => string | undefined;
}

export function QHGridBody<Data extends ObjectLiteral, ATI>(
  props: QHGridBodyProps<Data, ATI>
) {
  const joinChar = '\u200C';
  const [hidden, setHidden] = useState<Record<string, boolean>>({});

  // Clear hidden when grouping changes!
  useOnChangeInRender(props.grouping, () => {
    setHidden({});
  });
  const handleToggle = (key: string) => () => {
    setHidden((prev) => ({ ...prev, [key]: !prev[key] }));
  };
  const curGroups: string[] = [];
  const groupAccessors = props.grouping.map((group) =>
    getFieldGroupValueFunction(group.field, group.type)
  );
  let curRow = 0;
  const rows = props.slicedData.map((item, idx) => {
    const groupValues = groupAccessors.map((accessor) => accessor(item));
    let isHidden = false;
    let hiddenGroupIndex = -1;
    for (let index = 0; index < groupValues.length; ++index) {
      const groupName = groupValues.slice(0, index + 1).join(joinChar);
      if (hidden[groupName]) {
        isHidden = true;
        hiddenGroupIndex = index;
        break;
      }
    }

    const groupDisplays: ReactNode[] = [];
    if (props.grouping.length) {
      let groupsToDisplay = -1;
      for (let index = 0; index < groupValues.length; ++index) {
        if (groupsToDisplay === -1 && curGroups[index] !== groupValues[index]) {
          groupsToDisplay = index;
        }
        if (groupsToDisplay >= 0) {
          curGroups[index] = groupValues[index];
        }
      }
      if (groupsToDisplay !== -1) {
        for (let index = groupsToDisplay; index < groupValues.length; ++index) {
          const group = props.grouping[index];
          const groupName = groupValues.slice(0, index + 1).join(joinChar);
          const value = groupValues[index];
          if (hiddenGroupIndex > -1 && index > hiddenGroupIndex) {
            continue;
          }
          groupDisplays.push(
            <tr key={`${group.title}${groupName}`}>
              {range(index).map((rangeIdx) => {
                return (
                  <th
                    className="qh-grouping-spacer"
                    key={rangeIdx}
                    // collapsing
                  />
                );
              })}
              <th
                onClick={handleToggle(groupName)}
                colSpan={
                  props.visibleColumns.length + props.grouping.length - index
                }
                className="qh-grouping-cell"
                // collapsing
              >
                <QIcon
                  name={`keyboard_arrow_${
                    hidden[groupName] ? 'right' : 'down'
                  }`}
                />
                <strong>
                  {group.title}: {value}
                </strong>
              </th>
            </tr>
          );
        }
      }
    }

    if (groupDisplays.length > 0) {
      // Reset index on each group - since they are basically a "start"...
      curRow = 0;
    }
    const rowLevelProps = props.rowLevelPropsCalc?.(item, curRow) || {};
    const rowLevelStyle = props.rowLevelStyleCalc?.(item, curRow);
    curRow += 1;
    const row = isHidden ? null : (
      <tr
        style={rowLevelStyle}
        onClick={(evt) => props.onRowClick?.(evt, item, props.startIndex + idx)}
        {...rowLevelProps}
        className={clsx(rowLevelProps.className, { odd: curRow % 2 === 0 })}
        key={props.itemKeyMap(item) || idx}
      >
        {props.grouping.map((_group, groupIdx) => {
          return <td className="qh-grouping-spacer" key={groupIdx} />;
        })}
        {props.visibleColumns.map((col) => {
          const template = getTemplate(col);
          return (
            <td key={col.id || col.title} {...col.cellAttributes}>
              {template === undefined
                ? getFieldValue(item, col.field, col.type)
                : template(
                    getFieldValue(item, col.field, col.type),
                    item,
                    props.additionalTemplateInfo
                  )}
            </td>
          );
        })}
      </tr>
    );
    if (groupDisplays.length === 0) {
      return row;
    }

    return [...groupDisplays, row];
  });
  return <>{rows}</>;
}
