import { useEffect, useState } from 'react';

export function useDebouncedValue<T>(value: T, time?: number): T {
  const [debouncedValue, setDebouncedValue] = useState(value);
  useEffect(() => {
    if (!time) return;
    const timerId = setTimeout(() => {
      setDebouncedValue(value);
    }, time);
    return () => {
      clearTimeout(timerId);
    };
  }, [value, time]);
  // Due to rules of hooks, we can't skip the hooks, but we can effectively ignore them!
  if (!time) {
    return value;
  }
  return debouncedValue;
}

/**
 * Calls onChange during render when the watch value changes by reference.
 *
 * This allows react to know to re-render the component instead of continuing to child components
 * if you set state in the onChange function.
 * @param watch
 * @param onChange
 */
export function useOnChangeInRender<T>(watch: T, onChange: (watch: T) => void) {
  const [prev, setPrev] = useState(watch);
  if (prev !== watch) {
    setPrev(watch);
    onChange(watch);
  }
}
