import clsx from 'clsx';
import {
  ReactEventHandler,
  ReactNode,
  forwardRef,
  useCallback,
  useEffect,
  useRef,
} from 'react';

export interface DialogProps {
  /**
   * Note: due to HTML limitations, this is not a *true* controlled component!
   * You can set the `open` prop to `false` to close the dialog, but you cannot
   * ignore the close event fired to close it, as it will *close* the dialog regardless.
   */
  open?: boolean;
  /**
   * If true, the dialog will be modal, meaning it will trap focus and prevent
   * the user from interacting with the rest of the page until it is closed.
   *
   * Changing this will not change whether the dialog is a modal if it is already open.
   */
  modal?: boolean;
  children?: ReactNode;
  className?: string;
  onClose?: () => void;
  //   onCancel?: () => void;
}
export const Dialog = forwardRef<HTMLDialogElement, DialogProps>(
  function Dialog({ open, modal, children, className, ...props }, forwardRef) {
    const ref = useRef<HTMLDialogElement | null>(null);
    const refCallback = useCallback(
      (node: HTMLDialogElement) => {
        if (typeof forwardRef === 'function') {
          forwardRef(node);
        } else if (forwardRef) {
          forwardRef.current = node;
        }
        ref.current = node;
      },
      [forwardRef]
    );
    useEffect(() => {
      if (ref.current) {
        if (open) {
          if (ref.current.open) {
            // it will throw if you try to open an already open dialog
            // so if it is already open and the `modal` prop changes,
            // it is best to not-support that use-case
            return;
          }
          if (modal) {
            ref.current.showModal();
          } else {
            ref.current.show();
          }
        } else {
          ref.current.close();
        }
      }
    }, [open, modal]);
    const onClose: ReactEventHandler<HTMLDialogElement> = () => {
      props.onClose?.();
    };
    return (
      <dialog
        ref={refCallback}
        className={clsx('qh-root qh-dialog', className)}
        onClose={onClose}
        // onCancel={props.onCancel}
      >
        {children}
      </dialog>
    );
  }
);
