import { useLayoutEffect, useState } from 'react';
import { QButton } from '../components/Button';
import { QIcon } from '../components/Icon';
import { Pagination } from '../components/Pagination';

const paginationOpts = [
  {
    text: '5',
    value: 5,
  },
  {
    text: '10',
    value: 10,
  },
  {
    text: '15',
    value: 15,
  },
  {
    text: '30',
    value: 30,
  },
  {
    text: '45',
    value: 45,
  },
  {
    text: '60',
    value: 60,
  },
  {
    text: '75',
    value: 75,
  },
  {
    text: '100',
    value: 100,
  },
  {
    text: '250',
    value: 250,
  },
  {
    text: '500',
    value: 500,
  },
  {
    text: '1000',
    value: 1000,
  },
];

interface FooterProps {
  activePage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
  itemsPerPage: number;
  onItemsPerPageChange: (itemsPerPage: number) => void;
  onReloadData?: () => void;
  realStartIndex: number;
  realEndIndex: number;
  numRows: number;
}
export function Footer({
  activePage,
  totalPages: numPages,
  onPageChange: handlePageChange,
  onItemsPerPageChange: handleItemsPerPageChange,
  onReloadData,
  itemsPerPage,
  numRows,
  realStartIndex,
  realEndIndex,
}: FooterProps) {
  const [footerRef, setFooterRef] = useState<HTMLDivElement | null>(null);
  const [resizeObserver] = useState(
    () =>
      new ResizeObserver((entries) => {
        entries.forEach((entry) => {
          const target = entry.target as HTMLDivElement;
          const [{ blockSize } = { blockSize: 0 }] = entry.borderBoxSize;
          const root = target.closest('.qh-root') as HTMLDivElement;
          if (root) {
            root.style.setProperty('--qh-footer-height', `${blockSize}px`);
          }
        });
      })
  );
  useLayoutEffect(() => {
    if (!footerRef) return;
    resizeObserver.observe(footerRef, { box: 'border-box' });
    return () => {
      resizeObserver.unobserve(footerRef);
    };
  }, [footerRef, resizeObserver]);
  return (
    <div className="qh-footer" ref={setFooterRef}>
      <Pagination
        activePage={activePage}
        totalPages={numPages}
        onPageChange={handlePageChange}
      />

      <span>
        <select
          onChange={(ev) => handleItemsPerPageChange(+ev.currentTarget.value)}
          value={itemsPerPage}
        >
          {paginationOpts.map((opt) => (
            <option value={opt.value} key={opt.value}>
              {opt.text}
            </option>
          ))}
        </select>
        &nbsp;<strong>Items Per Page</strong>
      </span>
      <span className="qh-spacer" />
      <span className="qh-footer-PageInfo">
        {realStartIndex + 1} - {realEndIndex} of {numRows} Items{' '}
      </span>
      {onReloadData && (
        <QButton compact onClick={onReloadData} variant="ghost">
          <QIcon name="refresh" />
        </QButton>
      )}
    </div>
  );
}
