import {
  HTMLAttributes,
  MouseEvent,
  ReactNode,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { QuickViewModal, QuickViewModalProps } from './QuickViewModal';
import { QButton } from './components/Button';
import { QIcon } from './components/Icon';
import { useAutoControlled } from './hooks/useAutoControlled';
import {
  BaseGrouping,
  FetchAsyncFunc,
  IconColorConfig,
  IconConfig,
  QuickView,
  QuickViewConfig,
  QuickViewsConfig,
  View,
} from './types';
import { fetchBasic, isCancel, toCSSVariable } from './utils';
import { QMenu, QMenuItem } from './components/Menu';
import { useLiveRef } from './hooks/useLiveRef';
import { baseIcons, baseIconColors } from './iconUtil';

const stubObj = {};
const sortOrderToRightType: { [key: string]: 'asc' | 'desc' } = {
  ascending: 'asc',
  descending: 'desc',
  asc: 'asc',
  desc: 'desc',
};

export interface QuickViewsProps {
  /**
   * A collection of views that are easily switched between. There are options to make them user-addable as well as remotely stored through a service and database. Setting this enables basic quick views. Quick Views work by changing the current setting of the grid to their view. They don't lock the grid to that view, however.
   */
  config?: QuickViewsConfig;
  /**
   * The Id with which to store the quickViews either locally or remotely. Setting this enables custom quick views.
   */
  id?: string;
  /**
   * The URL to use to GET quickViews/ PUT the updated quick views
   */
  url?: string;
  /**
   * The ID of the quick view to show. Makes the quick view controlled.
   * Prevents nonprogramtic changing of the quick view (this is useful for cases where you might want some other part of the app to control the current QV).
   */
  value?: string;
  /**
   * The ID of the default quick view to show upon first displaying the grid
   */
  defaultValue?: string;
  /**
   * The Id to use to save the quick views to the database using
   */
  ownerId?: string;
  /**
   * If set to true, disables the ability to create and edit quick views
   */
  disableChanges?: boolean;
  /**
   * If set to true, hides the menu entirely
   */
  disableMenu?: boolean;
  /**
   * A function to handle quick view changes. Will let you control which quick view is showing if you use the quickView prop.
   */
  onChange?: (quickView: string, config: QuickView) => void;

  onViewChange: (config: QuickView) => void;
  /**
   * An optional way to add a share button if you want to generate a link to the quick view.
   * It's only really useful with the quickViewURL and controlled quickviews, as you would be able to generate a link with the ownerId and quickView such that anyone can open it and see their quick views.
   * disableQuickViewEditing is also good for this.
   */
  onShare?: (quickView: string, config: QuickView) => void;
  /**
   * A function to get the current view settings
   */
  getView?: () => View;
  icons?: readonly IconConfig[];
  colors?: readonly IconColorConfig[];
  fetchAsync?: FetchAsyncFunc;
}

export function QuickViews({
  icons = baseIcons,
  colors = baseIconColors,
  ...props
}: QuickViewsProps) {
  const [modalOpen, setModalOpen] = useState(false);
  const [editView, setEditView] = useState<QuickView | undefined>(undefined);
  const [saving, setSaving] = useState(false);

  const getViewRef = useRef(props.getView);
  getViewRef.current = props.getView;

  const [customConfig, setCustomConfig] = useState<QuickViewsConfig>(stubObj);
  const customConfigRef = useRef(stubObj);
  const disableChanges =
    props.disableChanges || !props.id || (props.url && !props.ownerId);

  const config = useMemo(() => {
    if (!props.config) {
      return customConfig;
    } else if (!Object.keys(customConfig).length) {
      return props.config || customConfig;
    } else {
      return { ...props.config, ...customConfig };
    }
  }, [customConfig, props.config]);

  const iconMap = useMemo(() => {
    return icons.reduce((acc, icon) => {
      acc.set(icon.label, icon.iconName);
      return acc;
    }, new Map<string, ReactNode>());
  }, [icons]);
  const iconReplacements = useMemo(() => {
    return icons.reduce((acc, icon) => {
      if (typeof icon.iconName === 'string') {
        // Also for backwards compatibility
        // make it replace string with string
        acc.set(icon.iconName, icon.label);
      }
      if (icon.previousValues) {
        icon.previousValues.forEach((prev) => {
          acc.set(prev, icon.label);
        });
      }
      return acc;
    }, new Map<string, string>());
  }, [icons]);

  const colorReplacements = useMemo(() => {
    return colors.reduce((acc, color) => {
      if (color.previousValues) {
        color.previousValues.forEach((prev) => {
          acc.set(prev, color.value);
        });
      }
      return acc;
    }, new Map<string, string>());
  }, [colors]);

  const quickViews = useMemo<QuickView[]>(() => {
    return Object.entries(config).map(([name, qv]) => ({
      name,
      ...qv,
      icon: qv.icon ? (iconReplacements.get(qv.icon) ?? qv.icon) : undefined,
      color:
        qv.icon && qv.color
          ? (colorReplacements.get(qv.color) ?? qv.color)
          : undefined,
    }));
  }, [config, iconReplacements, colorReplacements]);

  const [value, setValue] = useAutoControlled<string>({
    defaultValue: props.defaultValue,
    value: props.value,
    initialValue: '',
  });
  const view = useMemo(
    () => quickViews.find((qv) => qv.name === value),
    [value, quickViews]
  );
  useEffect(() => {
    const onViewChange = props.onViewChange;
    if (view) {
      onViewChange(view);
    }
  }, [view, props.onViewChange]);
  const fetchAsync = useLiveRef<FetchAsyncFunc>(props.fetchAsync ?? fetchBasic);
  useEffect(() => {
    const abortController = new AbortController();
    (async () => {
      let remoteQuickViews: QuickViewsConfig = {} as QuickViewsConfig;
      if (props.id) {
        if (props.url && props.ownerId) {
          try {
            const url = new URL(props.url, window.location.href);
            url.searchParams.append('quickViewsId', props.id);
            url.searchParams.append('ownerId', props.ownerId);
            const request = new Request(url, {
              method: 'get',
              signal: abortController.signal,
              headers: {
                Accept: 'application/json',
                'Content-Type': 'application/json',
              },
            });

            const data = await fetchAsync.current('quickViews', request);
            if (!validateRemoteData(data)) {
              throw new Error(
                'Invalid data from the service requesting quickViews'
              );
            }
            remoteQuickViews = data;
          } catch (error) {
            if (!isCancel(error)) {
              console.error(error);
              alert('Failed to get quickviews from the service');
            }
          }
        } else {
          const storageKey = `${props.id}.quickViews`;
          remoteQuickViews = JSON.parse(
            localStorage.getItem(storageKey) || '{}'
          );
        }
      }
      Object.values(remoteQuickViews).forEach((qv) => {
        qv.view.grouping = qv.view.grouping?.map<BaseGrouping>(
          (group: BaseGrouping & { col_id?: string }) => ({
            colId: group.colId ?? group.col_id,
            sortOrder: group.sortOrder,
          })
        );
        qv.view.columns = qv.view.columns?.map(
          (col: { id: string; ID?: string; hidden: boolean }) => ({
            id: col.id ?? col.ID,
            hidden: col.hidden,
          })
        );
        qv.view.sortOrder =
          qv.view.sortOrder && sortOrderToRightType[qv.view.sortOrder];
      });
      customConfigRef.current = remoteQuickViews;
      setCustomConfig(remoteQuickViews);
    })();
    return () => abortController.abort();
  }, [props.ownerId, props.id, props.url, fetchAsync]);

  const handleChange = (qv: QuickView) => (_ev) => {
    if (qv.name === value) {
      props.onViewChange(qv);
    } else {
      props.onChange?.(qv.name, qv);
      setValue(qv.name);
    }
  };

  const handleCreate = () => {
    setEditView(undefined);
    setModalOpen(true);
  };

  async function handleQVChange(qvs: QuickViewsConfig) {
    // Save props to the service
    if (props.url) {
      setSaving(true);
      try {
        const request = new Request(props.url, {
          method: 'put',
          body: JSON.stringify({
            quickViewsId: props.id,
            ownerId: props.ownerId,
            quickViews: qvs,
          }),
          headers: {
            Accept: 'application/json',
            'Content-Type': 'application/json',
          },
        });
        const data = await fetchAsync.current('quickViews', request);
        if (!validateRemoteData(data)) {
          throw new Error('Invalid data from the service saving quickViews');
        }
        setCustomConfig(data);
      } catch (error) {
        console.error(error);
        alert('Failed to save quickviews to the service');
      } finally {
        setSaving(false);
      }
    } else {
      const storageKey = `${props.id}.quickViews`;
      localStorage.setItem(storageKey, JSON.stringify(qvs));
      setCustomConfig(qvs);
    }
  }

  const handleRemove = (qv: QuickView) => (ev: MouseEvent) => {
    ev.stopPropagation();
    const { name } = qv;
    const { [name]: _old, ...config } = customConfig;
    handleQVChange(config);
  };

  const handleEdit = (qv: QuickView) => (ev) => {
    ev.stopPropagation();
    setEditView(qv);
    setModalOpen(true);
  };

  const handleShare = (qv: QuickView) => (ev) => {
    ev.stopPropagation();
    props.onShare?.(qv.name, qv);
  };

  const handleEditQuickView: QuickViewModalProps['onEditQuickView'] = async (
    oldName,
    newName,
    group,
    icon,
    color,
    updateData
  ) => {
    const view = updateData ? getViewRef.current?.() : editView?.view;
    if (!view || disableChanges) {
      return;
    }
    const config: QuickViewConfig = {
      custom: true,
      group,
      icon,
      color,
      view,
    };
    const qvs = { ...customConfig, [newName]: config };
    if (oldName && oldName !== newName) {
      delete qvs[oldName];
    }
    await handleQVChange(qvs);
  };

  const quickViewGroups = useMemo(
    () =>
      quickViews.reduce((map, qv) => {
        const groupName = qv.group || '';
        if (!map.has(groupName)) {
          map.set(groupName, []);
        }
        map.get(groupName)?.push(qv);
        return map;
      }, new Map<string, QuickView[]>()),
    [quickViews]
  );

  const quickViewMenu = Array.from(quickViewGroups).map(
    ([groupName, qvGroup]) => {
      const items = qvGroup.map((qv) => {
        const isCustom =
          qv.custom && (!!props.onShare || !props.disableChanges);
        const icon = qv.icon && iconMap.get(qv.icon);
        return (
          <QMenuItem
            key={qv.name}
            onClick={handleChange(qv)}
            className="qh-dropdown-item"
            label={qv.name}
            prependLabel={
              icon && (
                <span
                  className="qh-icon"
                  style={{ color: qv.color && toCSSVariable(qv.color) }}
                >
                  {icon}
                </span>
              )
            }
            render={
              isCustom
                ? (itemProps) => (
                    <div {...(itemProps as HTMLAttributes<HTMLDivElement>)} />
                  )
                : undefined
            }
            appendLabel={
              <>
                <span className="qh-spacer" />
                {isCustom && (
                  <div style={{ display: 'flex' }}>
                    {props.onShare && (
                      <QButton
                        title="Share View"
                        compact
                        onClick={handleShare(qv)}
                        variant="ghost"
                      >
                        <QIcon name="share" />
                      </QButton>
                    )}
                    {!props.disableChanges && (
                      <QButton
                        title="Edit View"
                        compact
                        onClick={handleEdit(qv)}
                        variant="ghost"
                      >
                        <QIcon name="edit" />
                      </QButton>
                    )}
                    {!props.disableChanges && (
                      <QButton
                        title="Delete View"
                        compact
                        variant="ghost"
                        onClick={handleRemove(qv)}
                      >
                        <QIcon name="remove" color="red" />
                      </QButton>
                    )}
                  </div>
                )}
              </>
            }
          />
        );
      });
      if (groupName) {
        return (
          <QMenu
            key={groupName}
            className="qh-dropdown-item"
            label={groupName}
            style={{ display: 'flex', justifyContent: 'space-between' }}
          >
            {items}
          </QMenu>
        );
      } else {
        return items;
      }
    }
  );
  if (props.disableMenu || (!quickViews.length && disableChanges)) {
    return null;
  }
  return (
    <>
      {modalOpen && (
        <QuickViewModal
          open={modalOpen}
          onClose={() => setModalOpen((prev) => !prev)}
          quickViews={quickViews}
          onEditQuickView={handleEditQuickView}
          values={editView}
          icons={icons}
          colors={colors}
        />
      )}
      <QMenu
        label="Quick Views"
        prependLabel={<QIcon name="bolt" />}
        className="qh-button outlined"
      >
        {!disableChanges && (
          <QMenuItem
            label="Add Quick View"
            appendLabel={<QIcon name="add" color="green" />}
            onClick={handleCreate}
            disabled={saving}
          ></QMenuItem>
        )}
        {quickViewMenu}
      </QMenu>
    </>
  );
}

function validateRemoteData(data: unknown): data is QuickViewsConfig {
  if (!data || Array.isArray(data) || typeof data !== 'object') return false;
  return true;
}
