import {
  autoUpdate,
  flip,
  FloatingFocusManager,
  FloatingList,
  size,
  useClick,
  useDismiss,
  useFloating,
  useId,
  useInteractions,
  useListItem,
  useListNavigation,
  useRole,
  useTypeahead,
} from '@floating-ui/react';
import clsx from 'clsx';
import {
  createContext,
  CSSProperties,
  HTMLAttributes,
  ReactNode,
  useCallback,
  useContext,
  useMemo,
  useRef,
  useState,
} from 'react';
import { QIcon } from './Icon';
import { FilterValue } from '../FilterTypeConfig';
import { useAutoControlled } from '../hooks/useAutoControlled';
import { QButton } from './Button';

interface SelectContextValue<T extends FilterValue> {
  activeIndex: number | null;
  selectedIndex: number | null;
  getItemProps: ReturnType<typeof useInteractions>['getItemProps'];
  handleSelect: (value: T | null) => void;
  availableHeight: number | undefined;
}

const SelectContext = createContext<SelectContextValue<FilterValue>>(
  {} as SelectContextValue<FilterValue>
);

export type QSelectOption<T extends FilterValue> = {
  value: T;
  text: string;
  className?: string;
  disabled?: boolean;
  render?: ReactNode | ((option: QSelectOption<T>) => ReactNode);
};

export type QSelectProps<T extends FilterValue> = {
  options: QSelectOption<T>[];
  className?: string;
  style?: CSSProperties;
  id?: string;
  popoverClassName?: string;
  popoverStyle?: CSSProperties;
  onChange?: (value: T) => void;
  value?: T;
  /**
   * If true, the select will be cleared when the clear button is clicked.
   * @default false
   */
  clearable?: boolean;
  /**
   * The placeholder text to show when no value is selected.
   */
  placeholder?: string;
};
export function QSelect<T extends FilterValue>({
  options,
  popoverClassName,
  popoverStyle,
  onChange,
  value,
  clearable,
  placeholder,
  ...props
}: QSelectProps<T>) {
  const [isOpen, setIsOpen] = useState(false);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  // const [selectedValue, setSelectedValue] = useState<T | null>(null);
  const [selectedValue, setSelectedValueAuto] = useAutoControlled({
    value,
    defaultValue: null,
  });
  const setSelectedValue = useCallback(
    (value: T | null) => {
      onChange?.(value as T);
      setSelectedValueAuto(value);
    },
    [setSelectedValueAuto, onChange]
  );
  const selectedIndex = useMemo(() => {
    const index = options.findIndex((option) => option.value === selectedValue);
    return index === -1 ? null : index;
  }, [selectedValue, options]);
  const selectedOption =
    selectedIndex != null ? options[selectedIndex] : undefined;
  const [availableHeight, setAvailableHeight] = useState<number>();

  const { refs, floatingStyles, context } = useFloating({
    placement: 'bottom-start',
    open: isOpen,
    onOpenChange: setIsOpen,
    whileElementsMounted: autoUpdate,
    middleware: [
      flip(),
      size({
        apply({ availableHeight }) {
          setAvailableHeight(availableHeight);
        },
      }),
    ],
  });

  const elementsRef = useRef<Array<HTMLElement | null>>([]);
  const labelsRef = useRef<Array<string | null>>([]);

  const handleSelect = useCallback(
    (value: T | null) => {
      // setSelectedIndex(index);
      setSelectedValue(value);
      setIsOpen(false);
    },
    [setSelectedValue]
  );

  function handleTypeaheadMatch(index: number | null) {
    if (isOpen) {
      setActiveIndex(index);
    } else {
      const option = index == null ? null : options[index];
      handleSelect(option?.value ?? null);
    }
  }

  const listNav = useListNavigation(context, {
    listRef: elementsRef,
    activeIndex,
    selectedIndex,
    onNavigate: setActiveIndex,
  });
  const typeahead = useTypeahead(context, {
    listRef: labelsRef,
    activeIndex,
    selectedIndex,
    onMatch: handleTypeaheadMatch,
  });
  const click = useClick(context);
  const dismiss = useDismiss(context);
  const role = useRole(context, { role: 'listbox' });

  const { getReferenceProps, getFloatingProps, getItemProps } = useInteractions(
    [listNav, typeahead, click, dismiss, role]
  );

  const selectContext = useMemo(
    () => ({
      activeIndex,
      selectedIndex,
      getItemProps,
      handleSelect,
      availableHeight,
    }),
    [activeIndex, selectedIndex, getItemProps, handleSelect, availableHeight]
  );

  return (
    <>
      <div
        ref={refs.setReference}
        tabIndex={0}
        {...getReferenceProps(props)}
        className={clsx('qh-select', props.className)}
      >
        {selectedOption?.text ?? placeholder}
        <span className=".qh-select--action">
          {clearable && (
            <QButton
              variant="ghost"
              compact
              size="mini"
              type="button"
              aria-label="Clear"
              onClick={() => setSelectedValue(null)}
            >
              <QIcon name="close" />
            </QButton>
          )}
          <QIcon name="keyboard_arrow_down" />
        </span>
      </div>
      <SelectContext.Provider
        value={selectContext as SelectContextValue<FilterValue>}
      >
        {isOpen && (
          <FloatingFocusManager context={context} modal={false}>
            <div
              ref={refs.setFloating}
              style={{
                ...floatingStyles,
                maxHeight: availableHeight,
                overflowY: 'auto',
                ...popoverStyle,
              }}
              className={clsx('qh-root qh-popover', popoverClassName)}
              {...getFloatingProps()}
            >
              <FloatingList elementsRef={elementsRef} labelsRef={labelsRef}>
                {options.map((option) => {
                  return (
                    <Option
                      key={option.value}
                      label={option.text}
                      value={option.value}
                    >
                      {typeof option.render === 'function'
                        ? option.render(option)
                        : (option.render ?? option.text)}
                    </Option>
                  );
                })}
              </FloatingList>
            </div>
          </FloatingFocusManager>
        )}
      </SelectContext.Provider>
    </>
  );
}
type OptionProps<T extends FilterValue> = HTMLAttributes<HTMLButtonElement> & {
  children: ReactNode;
  label: string;
  value: T;
};
function Option<T extends FilterValue>({
  children,
  label,
  value,
  ...props
}: OptionProps<T>) {
  const id = useId();
  const { activeIndex, selectedIndex, getItemProps, handleSelect } =
    useContext(SelectContext);

  const { ref, index } = useListItem({ label });

  const active = activeIndex === index;
  const selected = selectedIndex === index;

  return (
    <button
      {...props}
      ref={ref}
      id={id}
      role="option"
      aria-selected={active && selected}
      tabIndex={active ? 0 : -1}
      className={clsx(
        'qh-dropdown-item',
        { active, selected },
        props.className
      )}
      {...getItemProps({ onClick: () => handleSelect(value) })}
    >
      <QIcon
        className="qh-check"
        name={selected ? 'check_box' : 'check_box_outline_blank'}
      />{' '}
      {children}
    </button>
  );
}
