import {
  autoUpdate,
  flip,
  FloatingFocusManager,
  FloatingList,
  FloatingNode,
  FloatingPortal,
  FloatingTree,
  offset,
  safePolygon,
  shift,
  useClick,
  useDismiss,
  useFloating,
  useFloatingNodeId,
  useFloatingParentNodeId,
  useFloatingTree,
  useHover,
  useInteractions,
  useListItem,
  useListNavigation,
  useMergeRefs,
  useRole,
  useTypeahead,
} from '@floating-ui/react';
import clsx from 'clsx';
import {
  ButtonHTMLAttributes,
  createContext,
  Dispatch,
  forwardRef,
  HTMLProps,
  ReactNode,
  SetStateAction,
  useContext,
  useEffect,
  useRef,
  useState,
  FocusEvent,
  MouseEvent,
  MouseEventHandler,
  RefCallback,
} from 'react';

const MenuContext = createContext<{
  getItemProps: (userProps?: HTMLProps<HTMLElement>) => Record<string, unknown>;
  activeIndex: number | null;
  setActiveIndex: Dispatch<SetStateAction<number | null>>;
  setHasFocusInside: Dispatch<SetStateAction<boolean>>;
  isOpen: boolean;
}>({
  getItemProps: () => ({}),
  activeIndex: null,
  setActiveIndex: () => {},
  setHasFocusInside: () => {},
  isOpen: false,
});

export interface QMenuProps {
  label: string;
  prependLabel?: ReactNode;
  appendLabel?: ReactNode;
  nested?: boolean;
  children?: ReactNode;
}

export const MenuComponent = forwardRef<
  HTMLButtonElement,
  QMenuProps & HTMLProps<HTMLButtonElement>
>(function MenuComponent(
  { children, label, prependLabel, appendLabel, ...props },
  forwardedRef
) {
  const [isOpen, setIsOpen] = useState(false);
  const [hasFocusInside, setHasFocusInside] = useState(false);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);

  const elementsRef = useRef<Array<HTMLButtonElement | null>>([]);
  const labelsRef = useRef<Array<string | null>>([]);
  const parent = useContext(MenuContext);

  const tree = useFloatingTree();
  const nodeId = useFloatingNodeId();
  const parentId = useFloatingParentNodeId();
  const item = useListItem();

  const isNested = parentId != null;

  const { floatingStyles, refs, context } = useFloating<HTMLButtonElement>({
    nodeId,
    open: isOpen,
    onOpenChange: setIsOpen,
    placement: isNested ? 'right-start' : 'bottom-start',
    middleware: [
      offset({ mainAxis: isNested ? 0 : 4, alignmentAxis: isNested ? 0 : 0 }),
      flip(),
      shift(),
    ],
    whileElementsMounted: autoUpdate,
  });

  const hover = useHover(context, {
    enabled: isNested,
    delay: { open: 75 },
    handleClose: safePolygon({ blockPointerEvents: true }),
  });
  const click = useClick(context, {
    event: 'mousedown',
    toggle: !isNested,
    ignoreMouse: isNested,
  });
  const role = useRole(context, { role: 'menu' });
  const dismiss = useDismiss(context, { bubbles: true });
  const listNavigation = useListNavigation(context, {
    listRef: elementsRef,
    activeIndex,
    nested: isNested,
    onNavigate: setActiveIndex,
  });
  const typeahead = useTypeahead(context, {
    listRef: labelsRef,
    onMatch: isOpen ? setActiveIndex : undefined,
    activeIndex,
  });

  const { getReferenceProps, getFloatingProps, getItemProps } = useInteractions(
    [hover, click, role, dismiss, listNavigation, typeahead]
  );

  // Event emitter allows you to communicate across tree components.
  // This effect closes all menus when an item gets clicked anywhere
  // in the tree.
  useEffect(() => {
    if (!tree) return;

    function handleTreeClick() {
      setIsOpen(false);
    }

    function onSubMenuOpen(event: { nodeId: string; parentId: string }) {
      if (event.nodeId !== nodeId && event.parentId === parentId) {
        setIsOpen(false);
      }
    }

    tree.events.on('click', handleTreeClick);
    tree.events.on('menuopen', onSubMenuOpen);

    return () => {
      tree.events.off('click', handleTreeClick);
      tree.events.off('menuopen', onSubMenuOpen);
    };
  }, [tree, nodeId, parentId]);

  useEffect(() => {
    if (isOpen && tree) {
      tree.events.emit('menuopen', { parentId, nodeId });
    }
  }, [tree, isOpen, nodeId, parentId]);

  return (
    <FloatingNode id={nodeId}>
      <button
        ref={useMergeRefs([refs.setReference, item.ref, forwardedRef])}
        tabIndex={
          !isNested ? undefined : parent.activeIndex === item.index ? 0 : -1
        }
        role={isNested ? 'menuitem' : undefined}
        data-open={isOpen ? '' : undefined}
        data-nested={isNested ? '' : undefined}
        data-focus-inside={hasFocusInside ? '' : undefined}
        className={clsx(
          isNested ? 'qh-dropdown-item' : 'qh-dropdown',
          props.className
        )}
        {...getReferenceProps(
          parent.getItemProps({
            ...props,
            onFocus(event: FocusEvent<HTMLButtonElement>) {
              props.onFocus?.(event);
              setHasFocusInside(false);
              parent.setHasFocusInside(true);
            },
          })
        )}
      >
        {prependLabel}
        {label}
        {appendLabel}
        {isNested && (
          <span aria-hidden style={{ marginLeft: 10, fontSize: 10 }}>
            ▶
          </span>
        )}
      </button>
      <MenuContext.Provider
        value={{
          activeIndex,
          setActiveIndex,
          getItemProps,
          setHasFocusInside,
          isOpen,
        }}
      >
        <FloatingList elementsRef={elementsRef} labelsRef={labelsRef}>
          {isOpen && (
            <FloatingPortal>
              <FloatingFocusManager
                context={context}
                modal={false}
                initialFocus={isNested ? -1 : 0}
                returnFocus={!isNested}
              >
                <div
                  ref={refs.setFloating}
                  className="qh-root qh-menu"
                  style={floatingStyles}
                  {...getFloatingProps()}
                >
                  {children}
                </div>
              </FloatingFocusManager>
            </FloatingPortal>
          )}
        </FloatingList>
      </MenuContext.Provider>
    </FloatingNode>
  );
});

export interface QMenuItemProps {
  label: string;
  prependLabel?: ReactNode;
  appendLabel?: ReactNode;
  disabled?: boolean;
  /**
   * Replace the default rendering of the button.
   * @param props
   * @returns
   */
  render?: (
    props: ButtonHTMLAttributes<HTMLButtonElement> & {
      ref: RefCallback<HTMLElement> | null;
    }
  ) => ReactNode;
  // /**
  //  * @default 'button'
  //  */
  // as?: keyof JSX.IntrinsicElements;
  onClick?: MouseEventHandler<HTMLButtonElement>;
}

/**
 * QMenuItem is a component that renders a menu item.
 *
 * This should be rendered within a QMenu component.
 */
export const QMenuItem = forwardRef<
  HTMLButtonElement,
  QMenuItemProps & ButtonHTMLAttributes<HTMLButtonElement>
>(function MenuItem(
  { label, disabled, prependLabel, appendLabel, render, ...props },
  forwardedRef
) {
  const menu = useContext(MenuContext);
  const item = useListItem({ label: disabled ? null : label });
  const tree = useFloatingTree();
  const isActive = item.index === menu.activeIndex;
  const itemProps: Parameters<NonNullable<QMenuItemProps['render']>>[0] = {
    ...props,
    ref: useMergeRefs([item.ref, forwardedRef]),
    type: 'button' as const,
    role: 'menuitem' as const,
    className: clsx('qh-dropdown-item', props.className),
    tabIndex: isActive ? 0 : -1,
    disabled,
    ...menu.getItemProps({
      onClick(event: MouseEvent<HTMLButtonElement>) {
        props.onClick?.(event);
        tree?.events.emit('click');
      },
      onKeyDown(event) {
        // Buttons already perform the click action on Enter and Space
        // so we don't need to do anything here.
        if (event.currentTarget.tagName === 'BUTTON') return;
        if (event.currentTarget !== event.target) return;
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          props.onClick?.(event as unknown as MouseEvent<HTMLButtonElement>);
          tree?.events.emit('click');
        }
      },
      onFocus(event: FocusEvent<HTMLButtonElement>) {
        props.onFocus?.(event);
        menu.setHasFocusInside(true);
      },
    }),
    children: (
      <>
        {prependLabel}
        {label}
        {appendLabel}
      </>
    ),
  };
  return render ? render(itemProps) : <button {...itemProps} />;
});

/**
 * QMenu is a component that renders a menu with items.
 *
 * You can nest it within another QMenu to create a submenu.
 * The QMenu doesn't support an `onClick` being added to it.
 * Instead add the `onClick`s to the individual menu items.
 *
 * @example
 * ```tsx
 * <QMenu label="File">
 *  <QMenuItem label="New" onClick={handleNew} />
 *  <QMenuItem label="Open" onClick={handleOpen} />
 *  <QMenuItem label="Save" onClick={handleSave} />
 * </QMenu>
 * ```
 */
export const QMenu = forwardRef<
  HTMLButtonElement,
  QMenuProps & HTMLProps<HTMLButtonElement>
>(function Menu(props, ref) {
  const parentId = useFloatingParentNodeId();

  if (parentId === null) {
    return (
      <FloatingTree>
        <MenuComponent {...props} ref={ref} />
      </FloatingTree>
    );
  }

  return <MenuComponent {...props} ref={ref} />;
});
